INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.2.72','cb','cb.adi.2','ЧБ Ади 2.72',72,'গীতা ভাগবত যে-যে-জনেতে পড়ায় ।
ভক্তির ব্যাখ্যান নাহি তাহার জিহ্বায় ॥৭২॥','гӣта̄ бха̄гавата йе-йе-джанете пад̣а̄йа
бхактира вйа̄кхйа̄на на̄хи та̄ха̄ра джихва̄йа',NULL,NULL),('cb.adi.2.73','cb','cb.adi.2','ЧБ Ади 2.73',73,'এইমত বিষ্ণুমায়া-মোহিত সংসার ।
দেখি’ ভক্ত-সব দুঃখ ভাবেন অপার ॥৭৩॥','эи-мата виш̣н̣у-ма̄йа̄-мохита сам̇са̄ра
декхи’ бхакта-саба дух̣кха бха̄вена апа̄ра',NULL,NULL),('cb.adi.2.74','cb','cb.adi.2','ЧБ Ади 2.74',74,'‘কেমনে এই জীব-সব পাইবে উদ্ধার ! ।
বিষয়-সুখেতে সব মজিল সংসার ॥৭৪॥','‘кемане эи джӣва-саба па̄ибе уддха̄ра!
виш̣айа-сукхете саба маджила сам̇са̄ра',NULL,NULL),('cb.adi.2.75','cb','cb.adi.2','ЧБ Ади 2.75',75,'বলিলেও কেহ নাহি লয় কৃষ্ণনাম ! ।
নিরবধি বিদ্যা-কুল করেন ব্যাখ্যান ॥’ ৭৫॥','балилео кеха на̄хи лайа кр̣ш̣н̣а-на̄ма!
ниравадхи видйа̄-кула карена вйа̄кхйа̄на',NULL,NULL),('cb.adi.2.76','cb','cb.adi.2','ЧБ Ади 2.76',76,'স্বকার্য্য করেন সব ভাগবতগণ ।
কৃষ্ণপূজা, গঙ্গাস্নান, কৃষ্ণের কথন ॥৭৬॥','сва-ка̄рйа карена саба бха̄гавата-ган̣а
кр̣ш̣н̣а-пӯджа̄, ган̇га̄-сна̄на, кр̣ш̣н̣ера катхана',NULL,NULL),('cb.adi.2.77','cb','cb.adi.2','ЧБ Ади 2.77',77,'সবে মেলি’ জগতেরে করে আশীর্ব্বাদ ।
‘শীঘ্র, কৃষ্ণচন্দ্র, কর সবারে প্রসাদ’ ॥৭৭॥','сабе мели’ джагатере каре а̄ш́ӣрва̄да
‘ш́ӣгхра, кр̣ш̣н̣а-чандра, кара саба̄ре праса̄да’',NULL,NULL),('cb.adi.2.78','cb','cb.adi.2','ЧБ Ади 2.78',78,'সেই নবদ্বীপে বৈসে বৈষ্ণবাগ্রগণ্য ।
‘অদ্বৈত আচার্য্য’ নাম, সর্ব্ব-লোকে ধন্য ॥৭৮॥','сеи навадвӣпе ваисе ваиш̣н̣ава̄граганйа
‘адваита ачарйа’ на̄ма, сарва-локе дханйа',NULL,NULL),('cb.adi.2.79','cb','cb.adi.2','ЧБ Ади 2.79',79,'জ্ঞান-ভক্তি-বৈরাগ্যের গুরু মুখ্যতর ।
কৃষ্ণভক্তি বাখানিতে যেহেন শঙ্কর ॥৭৯॥','джн̃а̄на-бхакти-ваира̄гйера гуру мукхйатара
кр̣ш̣н̣а-бхакти ва̄кха̄ните йехена ш́ан̇кара',NULL,NULL),('cb.adi.2.80','cb','cb.adi.2','ЧБ Ади 2.80',80,'ত্রিভুবনে আছে যত শাস্ত্রের প্রচার ।
সর্ব্বত্র বাখানে,—‘কৃষ্ণপদভক্তি সার’ ॥৮০॥','трибхуване а̄чхе йата ш́а̄стрера прача̄ра
сарватра ва̄кха̄не,—‘кр̣ш̣н̣а-пада-бхакти са̄ра’
парамо виш̣н̣ур эваикас
тадж джн̃а̄нам̇ мукти-са̄дхана
ш́а̄стра̄н̣а̄м̇ нирн̣айас тв эш̣а
тад анйан мохана̄йа хи',NULL,NULL),('cb.adi.2.81','cb','cb.adi.2','ЧБ Ади 2.81',81,'তুলসী-মঞ্জরী-সহিত গঙ্গাজলে ।
নিরবধি সেবে কৃষ্ণে মহা-কুতূহলে ॥৮১॥','туласӣ-ман̃джарӣ-сахита ган̇га̄-джале
ниравадхи севе кр̣ш̣н̣е маха̄-кутӯхале
туласӣ-дала-ма̄трен̣а
джаласйа чулукена ва̄
викрӣн̣ӣте свам а̄тма̄нам̇
бхактебхйо бхакта-ватсалах̣',NULL,NULL),('cb.adi.2.82','cb','cb.adi.2','ЧБ Ади 2.82',82,'হুঙ্কার করয়ে কৃষ্ণ-আবেশের তেজে ।
যে ধ্বনি ব্রহ্মা ভেদি’ বৈকুণ্ঠেতে বাজে ॥৮২॥','хун̇ка̄ра карайе кр̣ш̣н̣а-а̄веш́ера тедже
йе дхвани брахма̄н̣да бхеди’ ваикун̣т̣хете ба̄дже',NULL,NULL),('cb.adi.2.83','cb','cb.adi.2','ЧБ Ади 2.83',83,'যে-প্রেমের হুঙ্কার শুনিঞা কৃষ্ণ নাথ ।
ভক্তিবশে আপনে যে হইলা সাক্ষাৎ ॥৮৩॥','йе-премера хун̇ка̄ра ш́унин̃а̄ кр̣ш̣н̣а на̄тха
бхакти-ваш́е а̄пане йе хаила̄ са̄кш̣а̄т',NULL,NULL),('cb.adi.2.84','cb','cb.adi.2','ЧБ Ади 2.84',84,'অতএব অদ্বৈত—বৈষ্ণব-অগ্রগণ্য ।
নিখিল-ব্রহ্মাণ্ডে যাঁর ভক্তিযোগ ধন্য ॥৮৪॥','атаева адваита—ваишн̣ава-аграган̣йа
никхила-брахма̄н̣д̣е йа̄н̇ра бхакти-йога дханйа',NULL,NULL),('cb.adi.2.85','cb','cb.adi.2','ЧБ Ади 2.85',85,'এইমত অদ্বৈত বৈসেন নদীয়ায় ।
ভক্তিযোগশূন্য লোক দেখি’ দুঃখ পায় ॥৮৫॥','эи-мата адваита ваисена надӣйа̄йа
бхакти-йога-ш́ӯнйа лока декхи’ дух̣кха па̄йа',NULL,NULL),('cb.adi.2.86','cb','cb.adi.2','ЧБ Ади 2.86',86,'সকল সংসার মত্ত ব্যবহার-রসে ।
কৃষ্ণপূজা, কৃষ্ণভক্তি কারো নাহি বাসে ॥৮৬॥','сакала сам̇са̄ра матта вйаваха̄ра-расе
кр̣ш̣н̣а-пӯджа̄, кр̣ш̣н̣а-бхакти ка̄ро на̄хи ва̄се',NULL,NULL),('cb.adi.2.87','cb','cb.adi.2','ЧБ Ади 2.87',87,'বাশুলী পূজয়ে কেহ নানা উপহারে ।
মদ্য মাংস দিয়া কেহ যক্ষ পূজা করে ॥৮৭॥','ва̄ш́улӣ пӯджайе кеха на̄на̄ упаха̄ре
мадйа ма̄м̇са дийа̄ кеха йакш̣а-пӯджа̄ каре',NULL,NULL),('cb.adi.2.88','cb','cb.adi.2','ЧБ Ади 2.88',88,'নিরবধি নৃত্য, গীত, বাদ্য-কোলাহল ।
না শুনে কৃষ্ণের নাম পরম মঙ্গল ॥৮৮॥','ниравадхи нр̣тйа, гӣта, ва̄дйа-кола̄хала
на̄ ш́уне кр̣ш̣н̣ера на̄ма парама ман̇гала',NULL,NULL),('cb.adi.2.89','cb','cb.adi.2','ЧБ Ади 2.89',89,'কৃষ্ণ-শূন্য মঙ্গলে দেবের নাহি সুখ ।
বিশেষ অদ্বৈত মনে পায় বড় দুঃখ ॥৮৯॥','кр̣ш̣н̣а-ш́ӯнйа ман̇гале девера на̄хи сукха
виш́еш̣а адваита мане па̄йа бад̣а дух̣кха',NULL,NULL),('cb.adi.2.90','cb','cb.adi.2','ЧБ Ади 2.90',90,'স্বভাবে অদ্বৈত—বড় কারুণ্য-হৃদয় ।
জীবের উদ্ধার চিন্তে হইয়া সদয় ॥৯০॥','сва-бха̄ве адваита—бад̣а ка̄рун̣йа-хр̣дайа
джӣвера уддха̄ра чинте хаийа̄ садайа',NULL,NULL),('cb.adi.2.91','cb','cb.adi.2','ЧБ Ади 2.91',91,'“মোর প্রভু আসি’ যদি করে অবতার ।
তবে হয় এ-সকল জীবের উদ্ধার ॥৯১॥','‘мора прабху а̄си’ йади каре авата̄ра
табе хайа э-сакала джӣвера уддха̄ра',NULL,NULL),('cb.adi.2.92','cb','cb.adi.2','ЧБ Ади 2.92',92,'তবে ত’ ‘অদ্বৈত সিংহ’ আমার বড়াই ।
বৈকুণ্ঠ-বল্লভ যদি দেখাঙ হেথাই ॥৯২॥','табе та’ ‘адваита сим̇ха’ а̄ма̄ра бад̣а̄и
ваикун̣т̣ха-валлабха йади декха̄н̃а хетха̄и',NULL,NULL),('cb.adi.2.93','cb','cb.adi.2','ЧБ Ади 2.93',93,'আনিয়া বৈকুণ্ঠনাথ সাক্ষাৎ করিয়া ।
নাচিব, গাইব সর্ব্বজীব উদ্ধারিয়া” ॥৯৩॥','а̄нийа̄ ваикун̣т̣ха-на̄тха са̄кш̣а̄т карийа̄
на̄чиба, га̄иба сарва-джӣва уддха̄рийа̄',NULL,NULL),('cb.adi.2.94','cb','cb.adi.2','ЧБ Ади 2.94',94,'নিরবধি এইমত সঙ্কল্প করিয়া ।
সেবেন শ্রীকৃষ্ণ-পদ একচিত্ত হৈয়া ॥৯৪॥','ниравадхи эи-мата сан̇калпа карийа̄
севена ш́рӣ-кр̣ш̣н̣а-пада эка-читта хаийа̄',NULL,NULL),('cb.adi.2.95','cb','cb.adi.2','ЧБ Ади 2.95',95,'‘অদ্বৈতের কারণে চৈতন্য-অবতার’ ।
সেই প্রভু কহিয়াছেন বারবার ॥৯৫॥','‘адваитера ка̄ране чаитанйа авата̄ра’
сеи прабху кахийа̄чхена ба̄ра-ба̄ра',NULL,NULL),('cb.adi.2.96','cb','cb.adi.2','ЧБ Ади 2.96',96,'সেই নবদ্বীপে বৈসে পণ্ডিত শ্রীবাস ।
যাঁহার মন্দিরে হৈল চৈতন্য-বিলাস ॥৯৬॥','сеи навадвӣпе ваисе пан̣д̣ита ш́рӣва̄са
йа̄н̇ха̄ра мандире хаила чаитанйа-вила̄са',NULL,NULL),('cb.adi.2.97','cb','cb.adi.2','ЧБ Ади 2.97',97,'সর্ব্বকাল চারি ভাই গায় কৃষ্ণনাম ।
ত্রিকাল করয়ে কৃষ্ণপূজা, গঙ্গাস্নান ॥৯৭॥','сарва-ка̄ла ча̄ри бха̄и га̄йа кр̣ш̣н̣а-на̄ма
три-ка̄ла карйе кр̣ш̣н̣а-пӯджа̄, ган̇га̄-сна̄на',NULL,NULL),('cb.adi.2.100','cb','cb.adi.2','ЧБ Ади 2.100',100,'একে একে বলিতে হয় পুস্তক-বিস্তার ।
কথার প্রস্তাবে নাম লইব, জানি যাঁর ॥১০০॥','эке эке балите хайа пустака-виста̄ра
катха̄ра праста̄ве на̄ма лаиба, джа̄ни йа̄нра',NULL,NULL),('cb.adi.2.101','cb','cb.adi.2','ЧБ Ади 2.101',101,'সবেই স্বধর্ম্মপর, সবেই উদার ।
কৃষ্ণভক্তি বই কেহ না জানয়ে আর ॥১০১॥','сабеи сва-дхарма-пара, сабеи уда̄ра
кр̣ш̣н̣а-бхакти баи кеха на̄ джа̄найе а̄ра',NULL,NULL),('cb.adi.2.102','cb','cb.adi.2','ЧБ Ади 2.102',102,'সবে করে সবারে বান্ধব-ব্যবহার ।
কেহ কারো না জানেন নিজ-অবতার ॥১০২॥','сабе каре саба̄ре ба̄ндхава-вйаваха̄ра
кеха ка̄ро на джа̄нена ниджа-авата̄ра',NULL,NULL),('cb.adi.2.103','cb','cb.adi.2','ЧБ Ади 2.103',103,'বিষ্ণুভক্তিশূন্য দেখি’ সকল সংসার ।
অন্তরে দহয়ে বড় চিত্ত সবাকার ॥১০৩॥','виш̣н̣у-бхакти-ш́ӯнйа декхи’ сакала сам̇са̄ра
антаре дахайе бад̣а читта саба̄ка̄ра',NULL,NULL),('cb.adi.2.104','cb','cb.adi.2','ЧБ Ади 2.104',104,'কৃষ্ণকথা শুনিবেক হেন নাহি জন ।
আপনা-আপনি সবে করেন কীর্ত্তন ॥১০৪॥','кр̣ш̣н̣а-катха̄ ш́унибека хена на̄хи джана
а̄пана̄’-а̄пани сабе карена кӣртана',NULL,NULL),('cb.adi.2.105','cb','cb.adi.2','ЧБ Ади 2.105',105,'দুই-চারি দ থাকি’ অদ্বৈতসভায় ।
কৃষ্ণকথা-প্রসঙ্গে সকল দুঃখ যায় ॥১০৫॥','дуи ча̄ри дан̣д̣а тха̄ки’ адваита-сабха̄йа
кр̣ш̣н̣а-катха̄-прасан̇ге сакала дух̣кха йа̄йа',NULL,NULL),('cb.adi.2.106','cb','cb.adi.2','ЧБ Ади 2.106',106,'দগ্ধ দেখে সকল সংসার ভক্তগণ ।
আলাপের স্থান নাহি, করেন ক্রন্দন ॥১০৬॥','дагдха декхе сакала сам̇са̄ра бхакта-ган̣а
а̄ла̄пера стха̄на на̄хи, карена крандана',NULL,NULL),('cb.adi.2.107','cb','cb.adi.2','ЧБ Ади 2.107',107,'সকল বৈষ্ণব মেলি’ আপনি অদ্বৈতে ।
প্রাণিমাত্র কারে কেহ নারে বুঝাইতে ॥১০৭॥','сакала ваиш̣н̣ава мели’ а̄пани адваита
пра̄н̣и-ма̄тра ка̄ре кеха на̄ре буджха̄ите',NULL,NULL),('cb.adi.2.108','cb','cb.adi.2','ЧБ Ади 2.108',108,'দুঃখ ভাবি’ অদ্বৈত করেন উপবাস ।
সকল বৈষ্ণবগণে ছাড়ে দীর্ঘ শ্বাস ॥১০৮॥','дух̣кха бха̄ви’ адваита карена упава̄са
сакала ваиш̣н̣ава-ган̣е чха̄д̣е дӣргха ш́ва̄са',NULL,NULL),('cb.adi.2.109','cb','cb.adi.2','ЧБ Ади 2.109',109,'‘কেন বা কৃষ্ণের নৃত্য, কেন বা কীর্ত্তন ।
কারে বা বৈষ্ণব বলি, কিবা সঙ্কীর্ত্তন ’ ॥১০৯॥','‘кена ва̄ кр̣ш̣н̣ера нр̣тйа, кена ва̄ кӣртана?
ка̄ре ва̄ ваиш̣н̣ава бали’, киба̄ сан̇кӣртана?’',NULL,NULL),('cb.adi.2.110','cb','cb.adi.2','ЧБ Ади 2.110',110,'কিছু নাহি জানে লোক ধন-পুত্ত্র-আশে ।
সকল পাষণ্ডী মেলি’ বৈষ্ণবেরে হাসে ॥১১০॥','кичху на̄хи джа̄не лока дхана-путра-а̄ш́е
сакала па̄ш̣ан̣д̣ӣ мели’ ваиш̣н̣авере ха̄се',NULL,NULL),('cb.adi.2.111','cb','cb.adi.2','ЧБ Ади 2.111',111,'চারি ভাই শ্রীবাস মিলিয়া নিজ-ঘরে ।
নিশা হৈলে হরিনাম গায় উচ্চৈঃস্বরে ॥১১১॥','ча̄ри бха̄и ш́рӣва̄са милийа ниджа-гхаре
